import { resolvePath } from "@typespec/compiler";
import { createTester, expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";

/**
 * A tester that includes @typespec/events so @events unions compile correctly.
 * Component names must end in a recognized suffix (-service, -cli, etc.)
 */
const EventsTester = createTester(resolvePath(import.meta.dirname, "../.."), {
  libraries: ["@a10n/blueprint-typespec", "@a10n/typespec-dbml", "@typespec/events"],
})
  .importLibraries()
  .using("State")
  .using("TypeSpec.Events");

// A @component with an @events union and a @worker namespace.
const EVENTS_SETUP = `
  @component(#{ type: ComponentType.Service })
  namespace Components.LifecycleService {
    @events
    union LifecycleEvent {
      RunRequested: { id: string };
      RunCompleted: { result: string };
    }

    @worker
    namespace Workers {
    }
  }
`;

describe("@publishes decorator", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_publishes
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_01
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_publishes:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_event_model:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_calls_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_event_model:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_publishes:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_op_only:must
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_calls_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_op_only:must
  it("T015_01: @publishes on an op with a valid @events variant — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      ${EVENTS_SETUP}

      @publishes(Components.LifecycleService.LifecycleEvent.RunRequested)
      op start_run(): void;
    `);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_02
  it("T015_02: @publishes targeting a variant from a non-@events union — emits publishes-event-model", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      ${EVENTS_SETUP}

      // A union without @events — FakeEvent is a valid UnionVariant, but the union lacks @events
      union OtherUnion {
        FakeEvent: { x: string };
      }

      @publishes(OtherUnion.FakeEvent)
      op bad_op(): void;
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/publishes-event-model",
    });
  });

  // T015_03: @publishes targeting a plain model (not a UnionVariant at all) emits a diagnostic.
  // The TypeSpec type system rejects Model arguments for a `variant: UnionVariant` parameter
  // before the JS decorator body can run, so the emitted code is `invalid-argument` rather than
  // `publishes-event-model`. The spec intends `publishes-event-model`, but current TypeSpec
  // type validation fires first.
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_03
  it("T015_03: @publishes targeting a plain model (not a union variant) — emits invalid-argument", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      ${EVENTS_SETUP}

      // RequestPayload is a standalone model — not a UnionVariant, not part of any union.
      // @publishes only accepts variants of @events-decorated unions.
      model RequestPayload { id: string; }

      @publishes(RequestPayload)
      op bad_op(): void;
    `);
    // TypeSpec's type-system rejects a Model argument for `variant: UnionVariant`
    // before the decorator body can run — emits `invalid-argument`.
    expectDiagnostics(diagnostics, {
      code: "invalid-argument",
    });
  });

  it("@publishes accumulates multiple variants per op — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      ${EVENTS_SETUP}

      @publishes(Components.LifecycleService.LifecycleEvent.RunRequested)
      @publishes(Components.LifecycleService.LifecycleEvent.RunCompleted)
      op multi_event(): void;
    `);
  });
});

describe("@subscribes decorator", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_subscribes
  it("@subscribes inside a @worker namespace — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      ${EVENTS_SETUP}

      @component(#{ type: ComponentType.Service })
      @worker
      namespace Components.WorkerService {
        @subscribes
        op handle_event(event: Components.LifecycleService.LifecycleEvent.RunRequested): void;
      }
    `);
  });

  it("@subscribes outside a @worker namespace — emits subscribes-op-only", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      ${EVENTS_SETUP}

      // This op is at global scope, not inside a @worker namespace
      @subscribes
      op orphan_subscriber(): void;
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/subscribes-op-only",
    });
  });

  it("@subscribes inside a @worker namespace's child namespace — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      ${EVENTS_SETUP}

      @component(#{ type: ComponentType.Service })
      @worker
      namespace Components.WorkerService {
        namespace Handlers {
          @subscribes
          op handle_event(event: Components.LifecycleService.LifecycleEvent.RunRequested): void;
        }
      }
    `);
  });
});

describe("@worker decorator", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_worker
  it("@worker nested inside a @component namespace — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Service })
      namespace Components.ValidService {
        @worker
        namespace Workers {
        }
      }
    `);
  });

  it("@worker directly on a @component namespace — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Service })
      @worker
      namespace Components.WorkerOnlyService {
      }
    `);
  });

  it("@worker outside a @component — emits invalid-namespace-nesting", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      @worker
      namespace OrphanWorkers {
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
    });
  });
});

describe("worker config validation", () => {
  it("valid config with all required fields — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Service })
      namespace Components.FullWorkerService {
        @worker(#{
          concurrency: ConcurrencyMode.Parallel,
          ack: AckPolicy.AutoOnReturn
        })
        namespace Workers {
        }
      }
    `);
  });

  it("valid config with concurrency: OnePerKey and routing_key — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Service })
      namespace Components.KeyedWorkerService {
        @worker(#{
          concurrency: ConcurrencyMode.OnePerKey,
          routing_key: "tenant_id",
          ack: AckPolicy.Manual
        })
        namespace Workers {
        }
      }
    `);
  });

  it("missing concurrency — TypeSpec type-checker emits invalid-argument", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Service })
      namespace Components.NoConcurrencyService {
        @worker(#{
          ack: AckPolicy.AutoOnReturn
        })
        namespace Workers {
        }
      }
    `);
    // WorkerConfig declares concurrency as required; TypeSpec's type-checker
    // fires invalid-argument before the JS decorator body runs.
    expectDiagnostics(diagnostics, {
      code: "invalid-argument",
    });
  });

  it("missing ack — TypeSpec type-checker emits invalid-argument", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Service })
      namespace Components.NoAckService {
        @worker(#{
          concurrency: ConcurrencyMode.Parallel
        })
        namespace Workers {
        }
      }
    `);
    // WorkerConfig declares ack as required; TypeSpec's type-checker
    // fires invalid-argument before the JS decorator body runs.
    expectDiagnostics(diagnostics, {
      code: "invalid-argument",
    });
  });

  it("concurrency: OnePerKey without routing_key — emits worker-one-per-key-missing-routing-key", async () => {
    const runner = await EventsTester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Service })
      namespace Components.OnePerKeyNoRoutingService {
        @worker(#{
          concurrency: ConcurrencyMode.OnePerKey,
          ack: AckPolicy.Manual
        })
        namespace Workers {
        }
      }
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/worker-one-per-key-missing-routing-key",
    });
  });

  it("concurrency: Singleton without routing_key — no diagnostics", async () => {
    const runner = await EventsTester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Service })
      namespace Components.SingletonWorkerService {
        @worker(#{
          concurrency: ConcurrencyMode.Singleton,
          ack: AckPolicy.AutoOnReturn
        })
        namespace Workers {
        }
      }
    `);
  });
});
